const configResp = $('Fetch Channel Config').first().json;
const usersResp = $input.first().json;
const staticData = $getWorkflowStaticData('global');

staticData.allowedChannels = configResp.value || null;

// Cache workspace url + team id (from auth.test) so Normalize can build Slack
// permalinks. If auth.test failed these stay unset and links fall back to null.
const wsResp = $('Fetch Workspace Info').first().json;
if (wsResp && wsResp.ok !== false) {
  if (wsResp.url) staticData.workspaceUrl = wsResp.url.replace(/\/+$/, '');
  if (wsResp.team_id) staticData.teamId = wsResp.team_id;
}

const now = Date.now();
const cacheAge = now - (staticData.userMapUpdatedAt || 0);
if (usersResp.ok !== false && usersResp.members && cacheAge > 600000) {
  const map = {};
  for (const m of usersResp.members) {
    if (m.id && !m.deleted) {
      const p = m.profile || {};
      map[m.id] = {
        name: p.display_name || p.real_name || m.name || m.id,
        email: p.email || ''
      };
    }
  }
  staticData.userMap = map;
  staticData.userMapUpdatedAt = now;
}

return [{ json: { cursor: '' } }];

const staticData = $getWorkflowStaticData('node');
const executionId = $execution.id;
if (staticData.executionId !== executionId) {
  staticData.allChannels = [];
  staticData.executionId = executionId;
}
const page = $input.first().json;
const channels = page.channels || [];
const cursor = (page.response_metadata && page.response_metadata.next_cursor) || '';
staticData.allChannels.push(...channels);
if (cursor) {
  return [{ json: { cursor: cursor, _hasMore: true } }];
} else {
  const result = staticData.allChannels.slice();
  staticData.allChannels = [];
  return [{ json: { channels: result } }];
}

const allChannels = $input.first().json.channels || [];
const oldest = String(Math.floor((Date.now() - 259200000) / 1000));
const staticData = $getWorkflowStaticData('global');
const allowed = staticData.allowedChannels;
const lastPollTs = staticData.lastPollTs || oldest;
staticData.lastPollTs = String(Math.floor(Date.now() / 1000));

return allChannels
  .filter(c => {
    if (!c.id || c.is_member === false) return false;
    if (allowed && Array.isArray(allowed)) {
      return allowed.some(a => a.toLowerCase() === (c.name || '').toLowerCase());
    }
    return true;
  })
  .map(c => ({
    json: {
      channel_id: c.id,
      channel_name: c.name || c.id,
      oldest: oldest,
      last_poll_ts: lastPollTs
    }
  }));

const channelItems = $('Build Channel Items').all();
const responses = $input.all();
const threads = [];

for (let i = 0; i < responses.length; i++) {
  const channel = channelItems[i]?.json ?? {};
  const resp = responses[i].json;
  if (resp.ok === false) continue;
  const lastPollTs = channel.last_poll_ts || '0';
  const lastPollNum = parseFloat(lastPollTs);

  for (const msg of (resp.messages || [])) {
    if (msg.reply_count > 0 && msg.latest_reply) {
      if (parseFloat(msg.latest_reply) > lastPollNum) {
        threads.push({
          json: {
            channel_id: channel.channel_id,
            channel_name: channel.channel_name,
            thread_ts: msg.thread_ts || msg.ts,
            oldest: lastPollTs
          }
        });
      }
    }
  }
}

if (threads.length === 0) {
  return [{ json: { _no_threads: true, channel_id: '', thread_ts: '0', oldest: '0' } }];
}
return threads;

const userMap = $getWorkflowStaticData('global').userMap || {};
const workspaceUrl = $getWorkflowStaticData('global').workspaceUrl || '';
const teamId = $getWorkflowStaticData('global').teamId || '';
function resolveUser(uid) {
  return userMap[uid] || { name: uid, email: '' };
}
function resolveText(text) {
  return (text || '').replace(/<@(U[A-Z0-9]+)>/g, (_, uid) => {
    const u = resolveUser(uid);
    return '@' + u.name;
  });
}

const channelItems = $('Build Channel Items').all();
const channelResponses = $('Fetch Messages').all();
const threadItems = $('Extract Active Threads').all();
const threadResponses = $input.all();
const allEvents = [];
const seenIds = new Set();

function addEvent(msg, channelId, channelName) {
  if (!msg.ts || msg.type !== 'message') return;
  const skipSubtypes = ['channel_join', 'channel_leave', 'channel_topic', 'channel_purpose', 'bot_add', 'bot_remove'];
  if (msg.subtype && skipSubtypes.includes(msg.subtype)) return;

  const eventId = 'evt_slack_' + msg.ts.replace('.', '_') + '_' + channelId;
  if (seenIds.has(eventId)) return;
  seenIds.add(eventId);

  const sender = resolveUser(msg.user);
  const resolvedText = resolveText(msg.text || '');
  const msgTime = new Date(parseFloat(msg.ts) * 1000);

  let rawEventType = 'message_received';
  if (msg.thread_ts && msg.thread_ts !== msg.ts) {
    rawEventType = 'thread_reply';
  } else if ((msg.text || '').includes('<@')) {
    rawEventType = 'mention';
  }

  let channelType = 'channel';
  if (channelId.startsWith('D')) channelType = 'dm';
  else if (channelId.startsWith('G')) channelType = 'mpim';

  // Canonical Slack permalink (message ts with the dot stripped, prefixed 'p');
  // thread params keep replies in thread context. Empty workspaceUrl (auth.test
  // failed / not yet cached) leaves url null, falling back to plain-text display.
  let subjectUrl = null;
  if (workspaceUrl && msg.ts) {
    subjectUrl = workspaceUrl + '/archives/' + channelId + '/p' + msg.ts.replace('.', '');
    const threadTs = msg.thread_ts || msg.ts;
    if (threadTs && threadTs !== msg.ts) {
      subjectUrl += '?thread_ts=' + threadTs + '&cid=' + channelId;
    }
  }

  allEvents.push({
    json: {
      event_id: eventId,
      timestamp: msgTime.toISOString(),
      source: {
        platform: 'slack',
        connection_id: $workflow.id,
        raw_event_type: rawEventType
      },
      actor: {
        name: sender.name,
        email: sender.email,
        platform_handle: msg.user || ''
      },
      subject: {
        type: 'thread',
        id: 'thread-' + channelId + '-' + (msg.thread_ts || msg.ts),
        title: resolvedText.substring(0, 80),
        url: subjectUrl
      },
      content: {
        body: resolvedText,
        attachments: [],
        metadata: {
          slack_channel: channelId,
          slack_team_id: teamId,
          slack_channel_name: channelName,
          slack_channel_type: channelType,
          slack_thread_ts: msg.thread_ts || msg.ts,
          slack_message_ts: msg.ts,
          slack_is_mention: (msg.text || '').includes('<@'),
          participants: [
            { role: 'sender', name: sender.name, email: sender.email, handle: msg.user || '' }
          ]
        }
      }
    }
  });
}

for (let i = 0; i < channelResponses.length; i++) {
  const channel = channelItems[i]?.json ?? {};
  const resp = channelResponses[i].json;
  if (resp.ok === false) continue;
  const lastPollNum = parseFloat(channel.last_poll_ts || '0');
  for (const msg of (resp.messages || [])) {
    if (parseFloat(msg.ts) > lastPollNum) {
      addEvent(msg, channel.channel_id || '', channel.channel_name || '');
    }
  }
}

for (let i = 0; i < threadItems.length; i++) {
  const item = threadItems[i].json;
  if (item._no_threads) continue;
  const resp = threadResponses[i].json;
  if (resp.ok === false) continue;
  for (const msg of (resp.messages || [])) {
    addEvent(msg, item.channel_id || '', item.channel_name || '');
  }
}

if (allEvents.length === 0) {
  return [{ json: { _skip: true } }];
}
return allEvents;
